import json, pathlib, sys, math
from collections import defaultdict
sys.path.insert(0,'/app/task_file/scripts')
from cost_model import CostModel, HEADS, HIDDEN, align
cm=CostModel(64)
root=pathlib.Path('/app/task_file')
thresholds={'requests_bucket_1.jsonl':2.1e6,'requests_bucket_2.jsonl':2.1e5}
shape=2048
for in_name in thresholds:
    thr=thresholds[in_name]
    reqs=[json.loads(l) for l in open(root/'input_data'/in_name)]
    byS=defaultdict(list)
    for r in reqs:
        S=align(r['prompt_len'],64)
        # singleton latency without compile
        lat=cm.batch_metrics([r])['latencies'][0]+8
        byS[S].append((r,lat))
    plan=[]; bid=1
    for S,items in sorted(byS.items()):
        good=[r for r,lat in items if lat<=thr]
        bad=[r for r,lat in items if lat>thr]
        if good:
            batch_id=f'b-{bid:04d}'; bid+=1
            sh={'seq_align':shape,'heads_align':HEADS,'hidden_align':HIDDEN}
            for r in good:
                plan.append({'request_id':r['request_id'],'batch_id':batch_id,'shape':sh})
        # exact prompt-gen groups for bad
        gb=defaultdict(list)
        for r in bad:
            gb[r['gen_len']].append(r)
        for g,rs in sorted(gb.items()):
            batch_id=f'b-{bid:04d}'; bid+=1
            sh={'seq_align':shape,'heads_align':HEADS,'hidden_align':HIDDEN}
            for r in rs:
                plan.append({'request_id':r['request_id'],'batch_id':batch_id,'shape':sh})
    reqmap={r['request_id']:r for r in reqs}
    m=cm.plan_metrics(reqmap, plan)
    print(in_name,'batches',bid-1,{k:m[k] for k in ['cost','pad_ratio','p95_latency_ms','sequential_timecost']})
